import{_ as o,o as t,c as a,an as n}from"./chunks/framework.ALAqWUP_.js";const u=JSON.parse('{"title":"Developer FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"developer/faq.md","filePath":"developer/faq.md","lastUpdated":null}'),s={name:"developer/faq.md"};function r(d,e,c,i,l,p){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="developer-faq" tabindex="-1">Developer FAQ <a class="header-anchor" href="#developer-faq" aria-label="Permalink to &quot;Developer FAQ {#developer-faq}&quot;">​</a></h1><p>Short answers to environment questions that come up when developing this package.</p><h2 id="Why-is-there-no-test/Manifest.toml?" tabindex="-1">Why is there no <code>test/Manifest.toml</code>? <a class="header-anchor" href="#Why-is-there-no-test/Manifest.toml?" aria-label="Permalink to &quot;Why is there no `test/Manifest.toml`? {#Why-is-there-no-test/Manifest.toml?}&quot;">​</a></h2><p>This package uses a Julia 1.12 workspace: <code>Project.toml</code> declares <code>[workspace] projects = [&quot;test&quot;, &quot;docs&quot;]</code>, so the <code>test</code> and <code>docs</code> sub-projects resolve against the shared root <code>Manifest.toml</code> rather than a manifest of their own. Pkg never writes or reads a per-member manifest under a workspace, so a <code>test/Manifest.toml</code> on disk is a stale leftover from before the workspace migration (or from a manual <code>Pkg.instantiate()</code> run inside <code>test/</code>) and can be deleted. It is already covered by the repository&#39;s <code>.gitignore</code>, so it never gets committed either way.</p><h2 id="I-pulled-main-after-a-cross-repo-dependency-change-and-something-looks-stale" tabindex="-1">I pulled <code>main</code> after a cross-repo dependency change and something looks stale <a class="header-anchor" href="#I-pulled-main-after-a-cross-repo-dependency-change-and-something-looks-stale" aria-label="Permalink to &quot;I pulled `main` after a cross-repo dependency change and something looks stale {#I-pulled-main-after-a-cross-repo-dependency-change-and-something-looks-stale}&quot;">​</a></h2><p>Check the <code>[sources]</code> block in <code>Project.toml</code>. Entries pinned to <code>rev = &quot;main&quot;</code> (currently <code>ConvolvedDistributions</code> and <code>EpiAwareADTools</code>, kept there only until they register — see the comment above <code>[sources]</code>) are resolved once and then frozen in the local <code>Manifest.toml</code>. A plain <code>git pull</code> updates this repository&#39;s own source but does not touch that frozen resolution, so an upstream <code>rev = &quot;main&quot;</code> package can move on and your local environment will keep using the old git-tree-sha with no warning or error.</p><p>Run <code>Pkg.update()</code> (not just <code>Pkg.instantiate()</code>) after any change that touches a <code>rev = &quot;main&quot;</code> dependency upstream, and whenever a bug looks like it should have been fixed by someone else&#39;s merge. Skipping this step produced a real phantom-bug investigation once (#191); the underlying pin hazard is tracked at #193 and only goes away once the pinned packages register.</p>',7)])])}const m=o(s,[["render",r]]);export{u as __pageData,m as default};
